def _router_with_channel() -> tuple[DefaultAlertRouter, CollectingChannel, InMemoryAlertAuditLog]:
    audit = InMemoryAlertAuditLog()
    router = DefaultAlertRouter(audit_log=audit)
    channel = CollectingChannel(health_overrides={"latency_ms": "5"})
    router.register(channel)
    return router, channel, audit


def _signal(
    side: str = "BUY",
    *,
    quantity: float = 1.0,
    price: float = 100.0,
    confidence: float | None = None,
) -> StrategySignal:
    return StrategySignal(
        symbol="BTC/USDT",
        side=side,
        confidence=0.75 if confidence is None else confidence,
        metadata={"quantity": str(quantity), "price": str(price), "order_type": "market"},
    )


def _opportunity_autonomy_signal(
    mode: str,
    *,
    side: str = "BUY",
    assisted_approval: bool | None = None,
    include_mode: bool = True,
    include_decision_payload: bool = False,
    decision_effective_mode: str | None = None,
    decision_primary_reason: str | None = None,
    performance_guard_effective_mode: str | None = None,
    performance_guard_primary_reason: str | None = None,
    performance_guard_hard_breach: bool | None = None,
    performance_guard_blocked: bool | None = None,
    model_version: str | None = None,
    decision_source: str | None = None,
    decision_payload_model_version: str | None = None,
    decision_payload_decision_source: str | None = None,
    decision_payload_inference_model: str | None = None,
    decision_payload_inference_model_version: str | None = None,
) -> StrategySignal:
    signal = _signal(side=side)
    metadata: dict[str, object] = dict(signal.metadata)
    metadata["opportunity_shadow_record_key"] = "shadow-key-1"
    if include_mode:
        metadata["opportunity_autonomy_mode"] = mode
    if include_decision_payload:
        metadata["opportunity_autonomy_decision"] = {}
    if decision_effective_mode is not None:
        decision_payload = metadata.get("opportunity_autonomy_decision")
        if not isinstance(decision_payload, dict):
            decision_payload = {}
        decision_payload["effective_mode"] = decision_effective_mode
        metadata["opportunity_autonomy_decision"] = decision_payload
    if decision_primary_reason is not None:
        decision_payload = metadata.get("opportunity_autonomy_decision")
        if not isinstance(decision_payload, dict):
            decision_payload = {}
        decision_payload["primary_reason"] = decision_primary_reason
        metadata["opportunity_autonomy_decision"] = decision_payload
    if decision_payload_model_version is not None:
        decision_payload = metadata.get("opportunity_autonomy_decision")
        if not isinstance(decision_payload, dict):
            decision_payload = {}
        decision_payload["model_version"] = decision_payload_model_version
        metadata["opportunity_autonomy_decision"] = decision_payload
    if decision_payload_decision_source is not None:
        decision_payload = metadata.get("opportunity_autonomy_decision")
        if not isinstance(decision_payload, dict):
            decision_payload = {}
        decision_payload["decision_source"] = decision_payload_decision_source
        metadata["opportunity_autonomy_decision"] = decision_payload
    if decision_payload_inference_model is not None:
        decision_payload = metadata.get("opportunity_autonomy_decision")
        if not isinstance(decision_payload, dict):
            decision_payload = {}
        decision_payload["inference_model"] = decision_payload_inference_model
        metadata["opportunity_autonomy_decision"] = decision_payload
    if decision_payload_inference_model_version is not None:
        decision_payload = metadata.get("opportunity_autonomy_decision")
        if not isinstance(decision_payload, dict):
            decision_payload = {}
        decision_payload["inference_model_version"] = decision_payload_inference_model_version
        metadata["opportunity_autonomy_decision"] = decision_payload
    if (
        performance_guard_effective_mode is not None
        or performance_guard_primary_reason is not None
        or performance_guard_hard_breach is not None
        or performance_guard_blocked is not None
    ):
        decision_payload = metadata.get("opportunity_autonomy_decision")
        if not isinstance(decision_payload, dict):
            decision_payload = {}
        performance_guard_payload = decision_payload.get("performance_guard")
        if not isinstance(performance_guard_payload, dict):
            performance_guard_payload = {}
        if performance_guard_effective_mode is not None:
            performance_guard_payload["effective_mode"] = performance_guard_effective_mode
        if performance_guard_primary_reason is not None:
            performance_guard_payload["primary_reason"] = performance_guard_primary_reason
        if performance_guard_hard_breach is not None:
            performance_guard_payload["hard_breach"] = performance_guard_hard_breach
            performance_guard_payload["performance_guard_applied"] = True
        if performance_guard_blocked is not None:
            performance_guard_payload["blocked"] = performance_guard_blocked
            performance_guard_payload["performance_guard_applied"] = True
        decision_payload["performance_guard"] = performance_guard_payload
        metadata["opportunity_autonomy_decision"] = decision_payload
    metadata["opportunity_autonomy_primary_reason"] = f"reason:{mode}"
    if assisted_approval is not None:
        metadata["autonomy_assisted_approval"] = assisted_approval
    if model_version is not None:
        metadata["opportunity_model_version"] = model_version
    if decision_source is not None:
        metadata["opportunity_decision_source"] = decision_source
    signal.metadata = metadata
    return signal


def _upstream_governance_envelope(
    *,
    requested_mode: str | None = "live_autonomous",
    effective_mode: str | None = "live_assisted",
    downgraded: bool | None = True,
    primary_reason: str | None = "upstream_downgrade",
    downgrade_source: str | None = "governance",
    downgrade_step_count: int | None = 2,
    decision_source: str | None = None,
    inference_model: str | None = None,
    inference_model_version: str | None = None,
    blocking_reasons: object | None = None,
    warnings: object | None = None,
    evidence_summary: object | None = None,
) -> dict[str, object]:
    payload: dict[str, object] = {}
    if requested_mode is not None:
        payload["requested_mode"] = requested_mode
    if effective_mode is not None:
        payload["effective_mode"] = effective_mode
    if downgraded is not None:
        payload["downgraded"] = downgraded
    if primary_reason is not None:
        payload["primary_reason"] = primary_reason
    if downgrade_source is not None:
        payload["downgrade_source"] = downgrade_source
    if downgrade_step_count is not None:
        payload["downgrade_step_count"] = downgrade_step_count
    if decision_source is not None:
        payload["decision_source"] = decision_source
    if inference_model is not None:
        payload["inference_model"] = inference_model
    if inference_model_version is not None:
        payload["inference_model_version"] = inference_model_version
    if blocking_reasons is not None:
        payload["blocking_reasons"] = blocking_reasons
    if warnings is not None:
        payload["warnings"] = warnings
    if evidence_summary is not None:
        payload["evidence_summary"] = evidence_summary
    return payload


def _last_event(journal: CollectingDecisionJournal, event_type: str) -> Mapping[str, str]:
    events = [event for event in journal.export() if event.get("event") == event_type]
    assert events, f"Missing event {event_type}"
    return events[-1]


def _ranked_selection_events(journal: CollectingDecisionJournal) -> list[Mapping[str, str]]:
    return [
        event
        for event in journal.export()
        if event.get("event") == "ranked_autonomous_open_selection"
    ]


def _ranked_selection_shadow_keys(event: Mapping[str, str], field: str) -> list[str]:
    payload = json.loads(str(event.get(field) or "[]"))
    assert isinstance(payload, list)
    return [str(item) for item in payload]


def _has_runtime_decision_trace_for_shadow_key(
    journal: CollectingDecisionJournal, shadow_key: str
) -> bool:
    normalized_shadow_key = str(shadow_key).strip()
    if not normalized_shadow_key:
        return False
    deferred_decision_events = [
        event
        for event in journal.export()
        if str(event.get("order_opportunity_shadow_record_key") or "").strip()
        == normalized_shadow_key
        and event["event"] in {"signal_skipped", "opportunity_autonomy_enforcement"}
    ]
    if deferred_decision_events:
        return True
    for ranked_event in _ranked_selection_events(journal):
        if normalized_shadow_key in _ranked_selection_shadow_keys(
            ranked_event, "selected_shadow_keys"
        ) or normalized_shadow_key in _ranked_selection_shadow_keys(
            ranked_event, "loser_shadow_keys"
        ):
            return True
    return False


def _assert_single_ranked_selection_event_payload(
    journal: CollectingDecisionJournal,
    *,
    remaining_slots: str,
    candidate_count: str,
    selected_count: str,
    loser_count: str,
    selected_shadow_keys: list[str],
    loser_shadow_keys: list[str],
) -> None:
    ranked_selection_events = _ranked_selection_events(journal)
    assert len(ranked_selection_events) == 1
    ranked_selection_event = ranked_selection_events[0]
    assert ranked_selection_event["remaining_slots"] == remaining_slots
    assert ranked_selection_event["candidate_count"] == candidate_count
    assert ranked_selection_event["selected_count"] == selected_count
    assert ranked_selection_event["loser_count"] == loser_count
    assert _ranked_selection_shadow_keys(ranked_selection_event, "selected_shadow_keys") == (
        selected_shadow_keys
    )
    assert _ranked_selection_shadow_keys(ranked_selection_event, "loser_shadow_keys") == (
        loser_shadow_keys
    )
    assert (
        ranked_selection_event["ranking_basis"]
        == "expected_return_bps,expected_probability,signal_confidence,stable_tie_break_key"
    )
    assert (
        ranked_selection_event["ranked_mode_source"]
        == "enable_autonomous_open_ranked_selection_within_batch"
    )


_ORDER_PATH_EVENT_TYPES = {
    "order_submitted",
    "order_executed",
    "order_failed",
    "order_execution_result",
    "order_partially_executed",
}


def _request_shadow_keys(requests: Sequence[OrderRequest]) -> list[str]:
    keys: list[str] = []
    for request in requests:
        metadata = request.metadata if isinstance(request.metadata, Mapping) else {}
        shadow_key = str(metadata.get("opportunity_shadow_record_key") or "").strip()
        if shadow_key:
            keys.append(shadow_key)
    return keys


def _order_path_events_with_shadow_key(
    journal: CollectingDecisionJournal, shadow_key: str
) -> list[Mapping[str, str]]:
    return [
        event
        for event in journal.export()
        if event.get("event") in _ORDER_PATH_EVENT_TYPES
        and (
            str(event.get("order_opportunity_shadow_record_key") or "").strip() == shadow_key
            or str(event.get("proxy_correlation_key") or "").strip() == shadow_key
            or str(event.get("correlation_key") or "").strip() == shadow_key
        )
    ]


def _opportunity_attach_events_referencing_key(
    journal: CollectingDecisionJournal, correlation_key: str
) -> list[Mapping[str, str]]:
    normalized_key = str(correlation_key).strip()
    if not normalized_key:
        return []
    return [
        event
        for event in journal.export()
        if event.get("event") == "opportunity_outcome_attach"
        and normalized_key
        in {
            str(event.get("order_opportunity_shadow_record_key") or "").strip(),
            str(event.get("proxy_correlation_key") or "").strip(),
            str(event.get("partial_correlation_key") or "").strip(),
            str(event.get("final_correlation_key") or "").strip(),
            str(event.get("correlation_key") or "").strip(),
        }
    ]


def _assert_no_durable_artifacts_for_shadow_key(
    repository: OpportunityShadowRepository,
    *,
    shadow_key: str,
) -> None:
    assert all(row.correlation_key != shadow_key for row in repository.load_open_outcomes())
    assert all(row.correlation_key != shadow_key for row in repository.load_outcome_labels())


