def test_upstream_handoff_mixed_batch_e2e_contract_is_identical_in_controller_and_persistence_regardless_of_order() -> (
    None
):
    class _MixedDecisionOrchestrator:
        def evaluate_candidate(self, candidate, _context):
            if candidate.symbol == "BTC/USDT":
                return SimpleNamespace(
                    candidate=candidate,
                    accepted=True,
                    reasons=(),
                    risk_flags=(),
                    stress_failures=(),
                    cost_bps=2.0,
                    net_edge_bps=9.0,
                    model_name="upstream-gbm-v2",
                    latency_ms=None,
                )
            return SimpleNamespace(
                candidate=candidate,
                accepted=False,
                reasons=("rejected_contract",),
                risk_flags=(),
                stress_failures=(),
                cost_bps=25.0,
                net_edge_bps=-2.0,
                model_name="upstream-gbm-v1",
                latency_ms=None,
            )

    decision_timestamp = datetime(2026, 1, 1, 12, 0, tzinfo=timezone.utc)
    accepted_key = OpportunityShadowRecord.build_record_key(
        symbol="BTC/USDT",
        decision_timestamp=decision_timestamp,
        model_version="opportunity-v1",
        rank=1,
    )
    rejected_key = OpportunityShadowRecord.build_record_key(
        symbol="ETH/USDT",
        decision_timestamp=decision_timestamp,
        model_version="rejected-shadow-v1",
        rank=2,
    )

    def _build_signal(symbol: str) -> StrategySignal:
        if symbol == "BTC/USDT":
            key = accepted_key
            inference_model = "accepted_model_v3"
            inference_model_version = "accepted_model_v3.1"
            decision_source = "accepted_governor_v2"
            expected_probability = 0.93
            expected_return_bps = 14.0
        else:
            key = rejected_key
            inference_model = "rejected_model_v9"
            inference_model_version = "rejected_model_v9.4"
            decision_source = "rejected_governor_v7"
            expected_probability = 0.51
            expected_return_bps = 1.0
        signal = _opportunity_autonomy_signal(
            "paper_autonomous",
            include_decision_payload=True,
            decision_payload_inference_model=inference_model,
            decision_payload_inference_model_version=inference_model_version,
            decision_payload_decision_source=decision_source,
        )
        signal.symbol = symbol
        signal.metadata = {
            **dict(signal.metadata),
            "quantity": "1.0",
            "price": "100.0",
            "order_type": "market",
            "expected_probability": expected_probability,
            "expected_return_bps": expected_return_bps,
            "opportunity_shadow_record_key": key,
            "opportunity_decision_timestamp": decision_timestamp.isoformat(),
        }
        return signal

    def _run(
        symbol_order: tuple[str, str],
    ) -> tuple[dict[str, object], dict[str, object], dict[str, object]]:
        sink = DecisionAwareSignalSink(
            base_sink=InMemoryStrategySignalSink(),
            orchestrator=_MixedDecisionOrchestrator(),
            risk_engine=DummyRiskEngine(),
            default_notional=1_000.0,
            environment="paper",
            exchange="BINANCE",
            min_probability=0.4,
            journal=CollectingDecisionJournal(),
            opportunity_shadow_adapter=None,
        )
        signals = tuple(_build_signal(symbol) for symbol in symbol_order)
        sink.submit(
            strategy_name="trend-d1",
            schedule_name="trend-d1",
            risk_profile="balanced",
            timestamp=decision_timestamp,
            signals=signals,
        )
        exported = sink.export()
        assert len(exported) == 1
        emitted = exported[0][1]
        assert [row.symbol for row in emitted] == ["BTC/USDT"]
        emitted_metadata = dict(emitted[0].metadata or {})
        assert emitted_metadata["opportunity_autonomy_mode"] == "paper_autonomous"
        assert emitted_metadata["opportunity_shadow_record_key"] == accepted_key
        assert emitted_metadata["opportunity_decision_timestamp"] == decision_timestamp.isoformat()
        assert emitted_metadata["expected_probability"] == 0.93
        assert emitted_metadata["expected_return_bps"] == 14.0
        assert (
            emitted_metadata["opportunity_autonomy_decision"]["inference_model"]
            == "accepted_model_v3"
        )
        assert (
            emitted_metadata["opportunity_autonomy_decision"]["inference_model_version"]
            == "accepted_model_v3.1"
        )
        assert (
            "rejected" not in emitted_metadata["opportunity_autonomy_decision"]["inference_model"]
        )

        shadow_repo = _autonomy_shadow_repository_with_final_outcomes(
            [4.0, 3.0], environment="paper", portfolio_id="paper-1"
        )
        shadow_repo.append_shadow_records(
            [
                _shadow_record_for_key(
                    correlation_key=accepted_key,
                    decision_timestamp=decision_timestamp,
                )
            ]
        )
        controller, execution, _journal = _build_autonomy_controller(
            environment="paper",
            opportunity_shadow_repository=shadow_repo,
        )
        results = controller.process_signals([emitted[0]])
        assert len(results) == 1
        request_metadata = dict(execution.requests[0].metadata or {})
        request_subset = {
            key: request_metadata.get(key)
            for key in (
                "opportunity_autonomy_mode",
                "opportunity_shadow_record_key",
                "opportunity_decision_timestamp",
                "expected_probability",
                "expected_return_bps",
                "opportunity_autonomy_decision",
            )
        }

        open_rows = shadow_repo.load_open_outcomes()
        assert len(open_rows) == 1
        provenance = dict(open_rows[0].provenance)
        provenance_subset = {
            key: provenance.get(key)
            for key in (
                "model_version",
                "decision_source",
                "upstream_autonomy_decision_source",
                "upstream_autonomy_inference_model",
                "upstream_autonomy_inference_model_version",
                "autonomy_requested_mode",
                "autonomy_final_mode",
            )
        }
        assert provenance_subset["upstream_autonomy_inference_model"] == "accepted_model_v3"
        assert (
            provenance_subset["upstream_autonomy_inference_model_version"] == "accepted_model_v3.1"
        )
        assert provenance_subset["decision_source"] == "accepted_governor_v2"
        assert provenance_subset["upstream_autonomy_decision_source"] == "accepted_governor_v2"

        return emitted_metadata, request_subset, provenance_subset

    first_run = _run(("BTC/USDT", "ETH/USDT"))
    second_run = _run(("ETH/USDT", "BTC/USDT"))

    assert first_run[0] == second_run[0]
    assert first_run[1] == second_run[1]
    assert first_run[2] == second_run[2]


def test_opportunity_autonomy_batch_cap_e2e_winner_only_downstream_without_loser_leakage() -> None:
    class _AcceptedOrchestrator:
        def evaluate_candidate(self, candidate, _context):
            return SimpleNamespace(
                candidate=candidate,
                accepted=True,
                reasons=(),
                risk_flags=(),
                stress_failures=(),
                cost_bps=0.0,
                net_edge_bps=float(getattr(candidate, "expected_return_bps", 0.0) or 0.0),
                model_name="batch-cap-e2e",
                latency_ms=None,
            )

    decision_timestamp = datetime(2026, 1, 2, 12, 0, tzinfo=timezone.utc)
    winner_key = OpportunityShadowRecord.build_record_key(
        symbol="BTC/USDT",
        decision_timestamp=decision_timestamp,
        model_version="batch-cap-v1",
        rank=1,
    )
    loser_key = OpportunityShadowRecord.build_record_key(
        symbol="ETH/USDT",
        decision_timestamp=decision_timestamp,
        model_version="batch-cap-v1",
        rank=2,
    )

    def _build_signal(symbol: str, key: str, expected_return_bps: float) -> StrategySignal:
        signal = _opportunity_autonomy_signal("paper_autonomous", include_decision_payload=True)
        signal.symbol = symbol
        signal.metadata = {
            **dict(signal.metadata),
            "quantity": "1.0",
            "price": "100.0",
            "order_type": "market",
            "expected_probability": 0.8,
            "expected_return_bps": expected_return_bps,
            "opportunity_shadow_record_key": key,
            "opportunity_decision_timestamp": decision_timestamp.isoformat(),
        }
        return signal

    def _shadow_record_for_symbol(symbol: str, key: str) -> OpportunityShadowRecord:
        return OpportunityShadowRecord(
            record_key=key,
            symbol=symbol,
            decision_timestamp=decision_timestamp,
            model_version="opportunity-v1",
            decision_source="opportunity_ai_shadow",
            expected_edge_bps=5.0,
            success_probability=0.7,
            confidence=0.3,
            proposed_direction="long",
            accepted=True,
            rejection_reason=None,
            rank=1,
            provenance={"probability_method": "test"},
            threshold_config=OpportunityThresholdConfig(),
            snapshot={},
            context=OpportunityShadowContext(environment="paper", notes={"portfolio": "paper-1"}),
        )

    sink_journal = CollectingDecisionJournal()
    sink = DecisionAwareSignalSink(
        base_sink=InMemoryStrategySignalSink(),
        orchestrator=_AcceptedOrchestrator(),
        risk_engine=DummyRiskEngine(),
        default_notional=1_000.0,
        environment="paper",
        exchange="BINANCE",
        min_probability=0.4,
        journal=sink_journal,
        opportunity_shadow_adapter=None,
        max_autonomous_open_winners_per_batch=1,
    )
    sink.submit(
        strategy_name="trend-d1",
        schedule_name="trend-d1",
        risk_profile="balanced",
        timestamp=decision_timestamp,
        signals=(
            _build_signal("BTC/USDT", winner_key, 15.0),
            _build_signal("ETH/USDT", loser_key, 7.0),
        ),
    )

    exported = sink.export()
    assert len(exported) == 1
    emitted = exported[0][1]
    assert [row.metadata.get("opportunity_shadow_record_key") for row in emitted] == [winner_key]

    repository = _autonomy_shadow_repository_with_final_outcomes(
        [4.0, 3.0], environment="paper", portfolio_id="paper-1"
    )
    repository.append_shadow_records(
        [
            _shadow_record_for_symbol("BTC/USDT", winner_key),
            _shadow_record_for_symbol("ETH/USDT", loser_key),
        ]
    )
    controller, execution, journal = _build_autonomy_controller(
        environment="paper",
        opportunity_shadow_repository=repository,
    )
    results = controller.process_signals(list(emitted))

    assert len(results) == 1
    assert [
        request.metadata.get("opportunity_shadow_record_key") for request in execution.requests
    ] == [winner_key]
    order_events = [
        event
        for event in journal.export()
        if event.get("event")
        in {
            "order_submitted",
            "order_executed",
            "order_failed",
            "order_execution_result",
            "order_partially_executed",
        }
    ]
    assert {event.get("order_opportunity_shadow_record_key") for event in order_events} == {
        winner_key
    }
    assert all(
        event.get("order_opportunity_shadow_record_key") != loser_key for event in order_events
    )

    open_rows = repository.load_open_outcomes()
    assert [row.correlation_key for row in open_rows] == [winner_key]
    all_labels = repository.load_outcome_labels()
    assert all(label.correlation_key != loser_key for label in all_labels)


