    alert_contexts_snapshot = [
        dict(message.context)
        for message in channel_1.messages
        if getattr(message, "category", "") == "execution"
        and str(message.context.get("meta_opportunity_shadow_record_key") or "").strip()
        == correlation_key
    ]

